var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그래서 뒷일은 어떻게 됐죠?","JPN":"……それで、その後はどうなったんですか？","ENG":"So what happened afterwards?","TWN":"……所以，後來怎麼樣了？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 나이엘은 한 달 동안 근신 및 봉사활동 처분이래.","JPN":"ナイエルは1ヶ月の謹慎と校内奉仕の処分だって。","ENG":"Well, Naielle has been grounded and has to do volunteer service for a month.","TWN":"嗯，處分的結果是奈爾被禁足一個月，還要進行志願活動。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 미카는 공로를 인정받아서 마술 대공연을 펼칠 행사 예산을 지원 받기로 했고.","JPN":"そしてミカは貢献を認められてマジックショーの開催費用を援助してもらうことになったんだけど。","ENG":"As for Mika, she earned recognition for her valor and secured funding for an upcoming magic show.","TWN":"還有米卡的功勞被認可，得到了魔術公演的活動預算支援。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......나이엘한테 걸었던 최면이 안 풀려서 풀릴 때까지 걔랑 봉사활동 다니게 됐지만.","JPN":"……ナイエルにかけた催眠がまだ解けてないから、校内奉仕にも同行することになったらしい。","ENG":"Although she ended up having to accompany Naielle till her hypnosis can wear off.","TWN":"……不過因為對奈爾的催眠無法解除，所以還得繼續研究怎麼改良。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"차림새랑 다르게 학생회장이 일처리가 엄청 빠르더라.","JPN":"生徒会長の仕事ぶりが思っていた以上に速くてびっくりだよ｡","ENG":"The Student President really gets things done quickly, despite her choice of clothing.","TWN":"不同於她的著裝，辦事效率非常高。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그렇군요.","JPN":"ハハハ……そうなんですね。","ENG":"Hah hah, I see.","TWN":"哈哈，原來如此。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 그 정도 대형 사고를 쳤는데 겨우 한 달 근신으로 끝나나요?","JPN":"それにしてもあんな大事件を起こしたのに､たった1ヶ月の謹慎で済むんですか？","ENG":"But will one month of detention be enough to address such a serious offense?","TWN":"可是這次奈爾闖了這麼大的禍，只禁足一個月嗎？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"퇴학 처분을 받아도 이상하지 않을 것 같은데.","JPN":"退学処分を受けてもおかしくないと思いましたが。","ENG":"You'd think she could be expelled for that sort of thing.","TWN":"就算被退學我也不會感到奇怪。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내가 처벌을 줄여 달라고 징계위원회에 부탁했어.","JPN":"……私が処分を軽くしてほしいと、懲戒委員会に頼んだよ。","ENG":"Well... I asked the disciplinary board for leniency.","TWN":"……是因為我向懲戒委員會請求對她從輕處理。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네? 정말인가요?","JPN":"え？　本当ですか？","ENG":"Huh? Really?","TWN":"啊？真的嗎？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 직접적인 피해자잖아요. 그런데 왜?","JPN":"ミナさんが一番の被害者なのに、なぜ？","ENG":"But you're one of the victims, Mina. Why did you do that?","TWN":"米娜可是直接受害人呢。為什麼？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 본인도 반성하고 있는 모양이고......","JPN":"まぁ、本人も反省しているようだし……","ENG":"Well, she seems sorry about what she did...","TWN":"嗯，因為我看到她本人也有在反省……"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"퇴각할 때 미카와 레이 선배를 위해 싸워 주기도 했으니까.","JPN":"退却する時、ミカとレイ先輩のために一応戦ってくれたからね。","ENG":"And she fought to protect Mika and Ray when they retreated.","TWN":"撤退的時候也為了米卡和雷伊前輩戰鬥過。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 왜 그렇게 쳐다 봐?","JPN":"な、なによ！　なんなの、その目は？","ENG":"W-what? Why are you staring at me like that?","TWN":"怎麼了？為什麼這麼看著我？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아닙니다. 전 또 나이엘 양의 저축을 탈탈 털었다거나 하는 이유였나 했거든요.","JPN":"何でもないですよ。てっきりナイエルさんと裏でお金の交渉でもしたのかなと思っていたので。","ENG":"Never mind. I thought you might have gotten Naielle to pay you everything she's got or something.","TWN":"沒什麼。我想說是不是你已經洗劫了奈爾的全部財產。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서윤 양이 들으면 섭섭해 하시겠네요.","JPN":"シズカさんが聞いたら残念がる理由でしたね。","ENG":"Seo Yoon will feel cheated if she hears about this.","TWN":"徐芸知道了會不高興吧。"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그 때 이야기는 좀 하지 말라니까!","JPN":"あ、あの時の話はもういいって！","ENG":"C-can you stop talking about that?","TWN":"能不能不再提那時候的事情了！"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그런데...... 그 레이 선배라는 분은 아직 연락이 안 되나요?","JPN":"ハハハ、ところで……あのレイ先輩という方とはまだ連絡がつかないんですか？","ENG":"Hah hah, by the way... Are you still having trouble getting in touch with this Ray person?","TWN":"哈哈，可是……現在還聯繫不到叫雷伊的那個前輩嗎？"},"stage":{"bg":"MAINSTREAM_6100012","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};